-- ESTUDIAR · Fase E-2 (FRANCÉS) — A1+A2 (unidades 1-12), SOLO DATOS.
-- La tabla study_theory y las RPCs de mig 178 son course-agnósticas por
-- construcción (derivan el curso de la unidad) → inglés y portugués intactos.
-- Los ejemplos traen la clave canónica `text` (idioma meta). NO toca motor FSRS,
-- economía, gating, certificación ni los otros idiomas. Prueba FORMATIVA.


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 1, 'A1', 'Bonjour y enchanté', 'Aprende a saludar, a elegir entre tu y vous, y a presentarte con être y «Je m''appelle…». En francés el pronombre sujeto nunca se omite.', '[{"heading": "Saludar según la hora", "body": "«Bonjour» sirve todo el día hasta el atardecer: en la tienda, en clase, con cualquiera. «Bonsoir» se usa por la tarde-noche, al llegar. «Salut» es informal: solo con amigos, familia o compañeros de tu edad. Al despedirte: «Au revoir» (neutro) o «Salut» (informal).", "bullets": ["Bonjour: de día, con todos, siempre seguro.", "Bonsoir: al llegar por la tarde o noche.", "Salut: solo con amigos; sirve para saludar y despedirse.", "Au revoir: adiós educado con cualquier persona."]}, {"heading": "Tu o vous: como tú y usted", "body": "Funciona casi igual que en español. «Tu» con amigos, familia y gente joven. «Vous» con desconocidos, en tiendas, con jefes o profesores. «Vous» también es el plural: hablando a varias personas, siempre vous, aunque sean amigos.", "bullets": ["Tu = tú: confianza, familia, amigos.", "Vous = usted: desconocidos, trabajo, comercios.", "Vous también es «vosotros»: varias personas.", "Ante la duda, usa vous: nunca es descortés."]}, {"heading": "Presentarse: être y je m''appelle", "body": "El verbo être (ser/estar): je suis, tu es, il est, elle est, vous êtes. El pronombre sujeto es obligatorio, aunque el español lo omita. Para el nombre: «Je m''appelle Ana». Al conocer a alguien: «Enchanté» si eres hombre, «Enchantée» si eres mujer.", "bullets": ["Je suis, tu es, il/elle est, vous êtes.", "Nunca frases sin sujeto: siempre je, tu, vous.", "Je m''appelle + tu nombre.", "Enchanté (hombre) / Enchantée (mujer): suenan igual."]}]'::jsonb, '[{"fr": "Bonjour, je m''appelle Ana. Enchantée !", "es": "Hola, me llamo Ana. ¡Encantada!", "text": "Bonjour, je m''appelle Ana. Enchantée !", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7ded33f1-fa0a-5b10-b0ef-f3741806030a.mp3"}, {"fr": "Salut ! Tu es espagnol ?", "es": "¡Hola! ¿Eres español?", "text": "Salut ! Tu es espagnol ?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f394aea7-1b06-53f0-a332-7c7a2ed10727.mp3"}, {"fr": "Bonsoir, madame. Vous êtes professeure ?", "es": "Buenas tardes, señora. ¿Es usted la profesora?", "text": "Bonsoir, madame. Vous êtes professeure ?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/81c339ac-dc5a-5cc9-8b83-daac8ab563d3.mp3"}, {"fr": "Elle est française et il est mexicain.", "es": "Ella es francesa y él es mexicano.", "text": "Elle est française et il est mexicain.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/814ef8f8-574f-51fc-8a9f-c39084dd9a7c.mp3"}]'::jsonb, '[{"title": "No quites el pronombre sujeto", "body": "En español dices «soy español» sin el «yo». En francés eso es imposible: «suis espagnol» está mal. Siempre «je suis espagnol», «tu es espagnol», «vous êtes espagnol». El sujeto viaja pegado al verbo."}, {"title": "Con un desconocido, vous", "body": "Muchos hispanohablantes tutean rápido. En Francia, tratar de «tu» a un camarero, a un vendedor o a un profesor suena brusco. Empieza con vous; si la otra persona propone «on peut se tutoyer ?», ya puedes pasar a tu."}, {"title": "La -e de enchantée", "body": "«Enchanté» y «enchantée» se pronuncian igual, así que es fácil olvidar la -e al escribir. Concuerda con quien HABLA, no con quien escucha: una mujer escribe «enchantée» aunque salude a un hombre."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Son las nueve de la mañana y entras en una panadería. ¿Cómo saludas?", "options": ["Bonjour", "Bonsoir", "Salut"], "answer": "Bonjour", "id": "u1q1"}, {"type": "multiple_choice", "prompt": "Ana se presenta a un compañero nuevo. ¿Qué escribe ella?", "options": ["Enchantée", "Enchanté", "Enchantés"], "answer": "Enchantée", "id": "u1q2"}, {"type": "cloze", "prompt": "Completa con el verbo être: «Yo soy español.»", "text": "Je ___ espagnol.", "answer": "suis", "accepted": ["suis"], "id": "u1q3"}, {"type": "cloze", "prompt": "Hablas a tu jefa (usted). Completa con el verbo être: «¿Es usted francesa?»", "text": "Vous ___ française ?", "answer": "êtes", "accepted": ["êtes", "etes"], "id": "u1q4"}, {"type": "cloze", "prompt": "Falta el pronombre sujeto (obligatorio en francés): «Me llamo Ana.»", "text": "___ m''appelle Ana.", "answer": "Je", "accepted": ["Je"], "id": "u1q5"}]'::jsonb)
