insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 5, 'A1', 'El día y la hora', 'Aprende a decir la hora en francés con «Il est … heures» y los minutos (et quart, et demie, moins le quart). Además, los días de la semana y cuándo llevan «le».', '[{"heading": "La hora: siempre «Il est»", "body": "En francés la hora es impersonal: siempre «il est» + número + «heures». Nunca «ils sont», aunque en español digamos «son las». Y «heures» no se omite. Solo «midi» (mediodía) y «minuit» (medianoche) van solos, sin «heures».", "bullets": ["Il est une heure. Il est trois heures.", "Il est midi. Il est minuit. Sin «heures».", "Para preguntar: «Quelle heure est-il ?»"]}, {"heading": "Los minutos: et quart, et demie, moins…", "body": "Con «quart» y «demie» se usa «et»: et quart, et demie. Con los demás minutos no se pone nada: «Il est trois heures dix». Para restar, «moins»; «le» solo ante «quart».", "bullets": ["Il est trois heures dix. (sin «et»)", "Il est neuf heures et quart.", "Il est six heures moins dix.", "Il est huit heures moins le quart."]}, {"heading": "Los días de la semana", "body": "Los días se escriben en minúscula: lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche. Sin artículo señalan un día concreto: «lundi» = este lunes. Con «le» delante indican costumbre: «le lundi» = todos los lunes.", "bullets": ["lundi = este lunes (un día concreto).", "le lundi = todos los lunes (costumbre).", "En francés los días no llevan mayúscula."]}]'::jsonb, '[{"fr": "Il est trois heures et demie.", "es": "Son las tres y media.", "text": "Il est trois heures et demie.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/210cc38f-0a99-51d1-89ac-e1a13c77a1ba.mp3"}, {"fr": "Il est midi et demi.", "es": "Es mediodía y media.", "text": "Il est midi et demi.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8fa662ba-5ad4-548e-b006-ff8cc3a2d9b1.mp3"}, {"fr": "Il est huit heures moins le quart.", "es": "Son las ocho menos cuarto.", "text": "Il est huit heures moins le quart.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8b0c4e45-fcea-5705-b90d-575ce41cde9c.mp3"}, {"fr": "Le lundi, j''ai un cours de français.", "es": "Los lunes tengo una clase de francés.", "text": "Le lundi, j''ai un cours de français.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/33bc9d03-b214-5a73-9cad-2931b5e0a452.mp3"}]'::jsonb, '[{"title": "«Ils sont trois heures» ✗", "body": "En español decimos «Son las tres», en plural. En francés el sujeto es impersonal: «Il est trois heures», siempre en singular. Y no olvides «heures»: «Il est trois» ✗ no significa nada."}, {"title": "«et demie» o «et demi»", "body": "Tras «heures» (femenino) se escribe «et demie»: «Il est deux heures et demie». Pero «midi» y «minuit» son masculinos, así que pierden la -e: «Il est midi et demi», «Il est minuit et demi»."}, {"title": "Los días van en minúscula", "body": "A diferencia del inglés, en francés se escribe «lundi», no «Lundi», salvo al empezar la frase. Y recuerda: «le samedi» = todos los sábados; «samedi» a secas = este sábado."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Son las tres». ¿Cómo se dice en francés?", "options": ["Il est trois heures.", "Ils sont trois heures.", "Il est trois."], "answer": "Il est trois heures.", "id": "u5q1"}, {"type": "multiple_choice", "prompt": "«Es mediodía y media». ¿Cuál es la forma correcta?", "options": ["Il est midi et demi.", "Il est midi et demie.", "Ils sont midi et demi."], "answer": "Il est midi et demi.", "id": "u5q2"}, {"type": "cloze", "prompt": "Completa con el verbo. La hora en francés es impersonal (Es mediodía).", "text": "Il ___ midi.", "answer": "est", "accepted": ["est"], "id": "u5q3"}, {"type": "cloze", "prompt": "Completa con la palabra que falta (Son las tres y media).", "text": "Il est trois ___ et demie.", "answer": "heures", "accepted": ["heures"], "id": "u5q4"}, {"type": "multiple_choice", "prompt": "«Los lunes tengo clase» (todos los lunes). ¿Cuál es correcta?", "options": ["Le lundi, j’ai un cours.", "Lundi, j’ai un cours.", "Les lundi, j’ai un cours."], "answer": "Le lundi, j’ai un cours.", "id": "u5q5"}]'::jsonb)
