insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 6, 'A1', 'Lugares y direcciones', 'Aprende a decir adónde vas con las contracciones obligatorias au, aux, du, des. Y a orientarte: à gauche, à droite, tout droit.', '[{"heading": "à + le = au, à + les = aux", "body": "Para decir «voy al cine» usas «à» + el artículo del lugar. Pero «à le» no existe en francés: las dos palabras se funden en una. Con «la» y «l''» no pasa nada: se escriben separadas.", "bullets": ["à + le = au: «Je vais au cinéma.»", "à + les = aux: «Je vais aux toilettes.»", "à + la = à la: «Je vais à la gare.»", "à + l'' = à l'': «Je vais à l''hôtel.»"]}, {"heading": "de + le = du, de + les = des", "body": "Lo mismo ocurre con «de» para decir de dónde vienes o dónde está algo. «De le» tampoco existe. Con «la» y «l''» se mantienen separadas, igual que antes.", "bullets": ["de + le = du: «Je viens du parc.»", "de + les = des: «près des magasins»", "de + la = de la: «en face de la banque»", "de + l'' = de l'': «à côté de l''école»"]}, {"heading": "Orientarse en la ciudad", "body": "Con estas palabras puedes dar y entender indicaciones básicas. Ojo: «tout droit» significa recto, seguir de frente; no es lo mismo que «à droite».", "bullets": ["à gauche = a la izquierda", "à droite = a la derecha", "tout droit = todo recto, de frente", "en face de / à côté de = enfrente de / al lado de"]}]'::jsonb, '[{"fr": "Je vais au restaurant avec Marie.", "es": "Voy al restaurante con Marie.", "text": "Je vais au restaurant avec Marie.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/113f7b4f-7b98-514f-8af9-3a306e02fb57.mp3"}, {"fr": "La pharmacie est en face de la gare.", "es": "La farmacia está enfrente de la estación.", "text": "La pharmacie est en face de la gare.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a379dc29-67bc-5dbc-8b50-0b09a6e15b1d.mp3"}, {"fr": "Continuez tout droit, puis tournez à gauche.", "es": "Siga todo recto, luego gire a la izquierda.", "text": "Continuez tout droit, puis tournez à gauche.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aca47fb8-dc39-5a07-8d40-6bffcc481642.mp3"}, {"fr": "Le musée est à côté du parc.", "es": "El museo está al lado del parque.", "text": "Le musée est à côté du parc.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d0d7301c-7b54-5f60-8e97-e2e74bf89d97.mp3"}]'::jsonb, '[{"title": "«à le» y «de le» NO existen", "body": "En español dices «a el» → «al», y en francés pasa igual pero es obligatorio: «Je vais au cinéma», nunca «à le cinéma». Igual con «de»: «du parc», nunca «de le parc». Con «la» y «l''» sí van separadas: «à la gare», «de l''hôtel»."}, {"title": "«tout droit» no es «à droite»", "body": "«Tout droit» significa TODO RECTO, seguir de frente. «À droite» significa A LA DERECHA. Si te dicen «tout droit» y giras a la derecha, te pierdes. Truco: «droit» solo = recto; «à droite» con la «e» final = derecha."}, {"title": "Falso amigo: «large» significa ANCHO", "body": "«Une rue large» es una calle ANCHA, no larga. Para decir largo se usa «long / longue»: «une longue rue» es una calle larga. No confundas: large = ancho, long = largo."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Voy al cine» en francés?", "options": ["Je vais au cinéma.", "Je vais à le cinéma.", "Je vais à la cinéma."], "answer": "Je vais au cinéma.", "id": "u6q1"}, {"type": "multiple_choice", "prompt": "Completa: «Elle parle ___ enfants» (à + les).", "options": ["aux", "au", "à les"], "answer": "aux", "id": "u6q2"}, {"type": "cloze", "prompt": "Completa con la contracción de de + le.", "text": "Je viens ___ parc.", "answer": "du", "accepted": ["du"], "id": "u6q3"}, {"type": "multiple_choice", "prompt": "El guía dice «Continuez tout droit». ¿Qué debes hacer?", "options": ["Seguir todo recto", "Girar a la derecha", "Girar a la izquierda"], "answer": "Seguir todo recto", "id": "u6q4"}, {"type": "multiple_choice", "prompt": "¿Qué significa «une rue large»?", "options": ["una calle ancha", "una calle larga", "una calle corta"], "answer": "una calle ancha", "id": "u6q5"}]'::jsonb)
