insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 7, 'A2', 'El pasado: lo que hice', 'Aprende el passé composé con AVOIR: el auxiliar en presente más el participio pasado. Es el pasado normal del francés hablado, el que usas para contar lo que hiciste ayer.', '[{"heading": "La fórmula: avoir + participio", "body": "Para contar algo terminado, junta el verbo avoir en presente con el participio del verbo. El participio de los verbos en -er termina en -é y el de los verbos en -ir termina en -i.", "bullets": ["j''ai, tu as, il a, nous avons, vous avez, ils ont", "manger → mangé · parler → parlé · regarder → regardé", "finir → fini · dormir → dormi · ojo: ouvrir → ouvert"]}, {"heading": "Los participios irregulares que más se usan", "body": "Varios verbos muy frecuentes tienen un participio propio que hay que memorizar. Son pocos, pero aparecen en casi toda conversación, así que conviene aprenderlos como bloque desde el primer día.", "bullets": ["faire → fait · prendre → pris · mettre → mis", "voir → vu · boire → bu · avoir → eu", "être → été: «J''ai été malade» (estuve enfermo)"]}, {"heading": "La negación abraza al auxiliar", "body": "En francés, ne y pas rodean el verbo conjugado. Aquí el verbo conjugado es avoir, no el participio. Por eso ne… pas se cierra antes del participio, que queda fuera, al final.", "bullets": ["je n''ai pas mangé · tu n''as pas vu · il n''a pas fait", "Con jamais y rien funciona igual: «je n''ai rien bu»", "Ne se vuelve n'' delante de vocal: n''ai, n''as, n''ont"]}]'::jsonb, '[{"fr": "Hier, j''ai mangé au restaurant avec ma sœur.", "es": "Ayer comí en el restaurante con mi hermana.", "text": "Hier, j''ai mangé au restaurant avec ma sœur.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/127ef4a2-d888-52dd-b317-62214a91cd23.mp3"}, {"fr": "Nous avons pris le train et nous avons vu la mer.", "es": "Tomamos el tren y vimos el mar.", "text": "Nous avons pris le train et nous avons vu la mer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b1766bb5-e76b-5f43-88e8-b03914418ff4.mp3"}, {"fr": "Je n''ai pas fait mes devoirs ce week-end.", "es": "No hice mis deberes este fin de semana.", "text": "Je n''ai pas fait mes devoirs ce week-end.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/da4cc358-3b39-54a6-8f0d-62e2479eb5e3.mp3"}, {"fr": "Elle a bu un café et elle a été surprise.", "es": "Ella se tomó un café y se quedó sorprendida.", "text": "Elle a bu un café et elle a été surprise.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ec2b67f1-8712-5565-b3e5-22dc2c56ef34.mp3"}]'::jsonb, '[{"title": "«Je n''ai mangé pas» ✗", "body": "En español dices «no he comido» y el «no» va al principio. En francés ne y pas encierran el AUXILIAR: «je n''ai pas mangé». El participio siempre queda después de pas, nunca en medio."}, {"title": "«J''ai manger» ✗ — escribe mangé", "body": "Manger y mangé suenan igual, pero después de avoir se escribe siempre el participio con acento: «j''ai mangé», «j''ai parlé», «j''ai regardé». El infinitivo en -er nunca va detrás del auxiliar."}, {"title": "No traduzcas el pretérito simple español", "body": "«Comí», «hice», «vi» no tienen una forma simple equivalente en el francés hablado. Todo eso se dice con passé composé: j''ai mangé, j''ai fait, j''ai vu. El passé simple solo vive en los libros."}, {"title": "Estos verbos van con être, no con avoir", "body": "Aller, partir, venir, arriver y otros de movimiento no usan avoir: se dice «je suis allé», nunca «j’ai allé». Los verás en su propia unidad."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál frase está bien escrita?", "options": ["J''ai mangé une pizza.", "J''ai manger une pizza.", "J''ai mangez une pizza."], "answer": "J''ai mangé une pizza.", "id": "u7q1"}, {"type": "multiple_choice", "prompt": "Pon en negativo: «Il a vu le film».", "options": ["Il n''a pas vu le film.", "Il n''a vu pas le film.", "Il a pas ne vu le film."], "answer": "Il n''a pas vu le film.", "id": "u7q2"}, {"type": "cloze", "prompt": "Completa con el participio del verbo ''faire''.", "text": "J''ai ___ mes devoirs hier soir.", "answer": "fait", "accepted": ["fait"], "id": "u7q3"}, {"type": "cloze", "prompt": "Completa con el participio del verbo ''prendre''.", "text": "Nous avons ___ le bus à huit heures.", "answer": "pris", "accepted": ["pris"], "id": "u7q4"}, {"type": "cloze", "prompt": "Completa con la negación y el auxiliar: ne/n’ + avoir (je) + pas.", "text": "Je ___ bu de café ce matin.", "answer": "n''ai pas", "accepted": ["n''ai pas"], "id": "u7q5"}]'::jsonb)
