insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 8, 'A2', 'Planes y futuro', 'Aprende a hablar del futuro en francés con el futur proche (je vais + infinitivo) y el futur simple (je parlerai), y a elegir cuál usar.', '[{"heading": "Futur proche: je vais + infinitivo", "body": "Es el futuro de la conversación diaria, igual que el español «voy a…». Se forma con el presente de aller (vais, vas, va, allons, allez, vont) seguido del infinitivo, sin nada en medio. Se usa para planes decididos y para lo que pasará muy pronto.", "bullets": ["Je vais manger, tu vas sortir, nous allons partir.", "Nunca pongas «à» entre aller y el infinitivo.", "Negación: je ne vais pas travailler demain."]}, {"heading": "Futur simple: infinitivo + terminaciones", "body": "Se añaden -ai, -as, -a, -ons, -ez, -ont al infinitivo COMPLETO: parler → je parlerai, tu parleras, il parlera, nous parlerons, vous parlerez, ils parleront. Los verbos en -re pierden solo la -e final: prendre → je prendrai.", "bullets": ["Finir → je finirai, tu finiras, ils finiront.", "Prendre → je prendrai (cae la -e, nada más).", "La -r- del infinitivo siempre se oye y se escribe."]}, {"heading": "Irregulares y cuándo usar cada uno", "body": "Seis verbos muy frecuentes cambian de base, pero llevan las mismas terminaciones: être→serai, avoir→aurai, aller→irai, faire→ferai, pouvoir→pourrai, venir→viendrai. El futur proche domina al hablar de planes; el futur simple es normal en promesas, previsiones y textos escritos.", "bullets": ["Je serai, j''aurai, j''irai, je ferai, je pourrai, je viendrai.", "Plan decidido o inmediato: futur proche.", "Promesa, previsión o texto escrito: futur simple.", "Los dos son correctos; cambian el tono, no la corrección."]}]'::jsonb, '[{"fr": "Ce soir, je vais regarder un film.", "es": "Esta noche voy a ver una película.", "text": "Ce soir, je vais regarder un film.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ef67a5ae-e68d-5f83-a77c-c1981bbe8043.mp3"}, {"fr": "Demain, nous allons partir tôt.", "es": "Mañana vamos a salir temprano.", "text": "Demain, nous allons partir tôt.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a859ac90-dafb-52d9-a6ae-7e89be44c84b.mp3"}, {"fr": "L''année prochaine, je parlerai bien français.", "es": "El año que viene hablaré bien francés.", "text": "L''année prochaine, je parlerai bien français.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/cfe73713-3291-55b2-bf9a-80f53985d440.mp3"}, {"fr": "Il fera beau samedi.", "es": "Hará buen tiempo el sábado.", "text": "Il fera beau samedi.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0d14c513-7a81-5cfe-b080-2f1dbf43ce62.mp3"}]'::jsonb, '[{"title": "«Je vais à manger» no existe", "body": "En español decimos «voy A comer», pero el francés une aller y el infinitivo directamente: «je vais manger». Ese «à» sobra siempre en el futur proche: on va sortir, elle va téléphoner, ils vont arriver."}, {"title": "La base del futur simple es el infinitivo entero", "body": "Se escribe «je parlerai», no «je parlrai»; «tu finiras», no «tu finras». No se pierde ninguna letra salvo la -e final de los verbos en -re: prendre → je prendrai, écrire → j''écrirai."}, {"title": "Los irregulares no siguen el infinitivo", "body": "Con être, avoir, aller, faire, pouvoir y venir hay que aprender la base: serai, aurai, irai, ferai, pourrai, viendrai. Nunca «êtrai» ni «allerai». Ojo también con los acentos: j''achèterai, je me lèverai (é → è)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta del futur proche?", "options": ["Je vais manger au restaurant.", "Je vais à manger au restaurant.", "Je vais de manger au restaurant."], "answer": "Je vais manger au restaurant.", "id": "u8q1"}, {"type": "cloze", "prompt": "Completa con el FUTUR SIMPLE del verbo ''parler'' (je).", "text": "Demain, je ___ avec le directeur.", "answer": "parlerai", "accepted": ["parlerai"], "id": "u8q2"}, {"type": "multiple_choice", "prompt": "Elige el futur simple correcto del verbo ''être'' con ''nous''.", "options": ["nous serons", "nous etrons", "nous serions"], "answer": "nous serons", "id": "u8q3"}, {"type": "cloze", "prompt": "Completa con el presente de ''aller'' (nous) para formar el futur proche.", "text": "Ce week-end, nous ___ visiter Paris.", "answer": "allons", "accepted": ["allons"], "id": "u8q4"}, {"type": "cloze", "prompt": "Completa con el FUTUR SIMPLE del verbo ''avoir'' (tu).", "text": "Tu ___ vingt ans en mai.", "answer": "auras", "accepted": ["auras"], "id": "u8q5"}]'::jsonb)
