insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 9, 'A2', 'De viaje', 'Los verbos de movimiento y de cambio de lugar forman el passé composé con ÊTRE, no con avoir. Con être, el participio concuerda con el sujeto: elle est allée, ils sont partis.', '[{"heading": "Un grupo de verbos usa ÊTRE", "body": "En passé composé casi todos los verbos usan avoir, pero un grupo de verbos de movimiento o de cambio de lugar usa être: aller, venir, partir, sortir, entrer, arriver, rester, monter, descendre, tomber, retourner, naître, mourir. En español todos llevan «haber», por eso hay que memorizar este grupo.", "bullets": ["Je suis allé, tu es venu, il est parti.", "«J''ai allé» no existe: siempre «je suis allé».", "Monter, sortir, rentrer usan avoir con complemento: «j’ai sorti la poubelle»."]}, {"heading": "Con être, el participio concuerda", "body": "Con être, el participio se comporta como un adjetivo: se le añade -e si el sujeto es femenino y -s si es plural. Con avoir no se añade nada: el participio no cambia nunca por el sujeto.", "bullets": ["Il est allé / elle est allée (se añade -e).", "Ils sont allés / elles sont allées (se añade -s).", "Elle a mangé: con avoir no se toca."]}, {"heading": "Viajar: rester, quitter, partir", "body": "Para hablar de un viaje necesitas tres verbos que confunden al hispanohablante. «Rester» significa quedarse. «Quitter» significa dejar un lugar o a alguien y siempre lleva complemento. «Partir» es irse, y suele ir con «de» o «pour».", "bullets": ["Je suis resté trois jours à Lyon.", "J''ai quitté Paris à midi (quitter usa avoir).", "Nous sommes partis pour Nice."]}]'::jsonb, '[{"fr": "Elle est arrivée à Paris hier soir.", "es": "Ella llegó a París ayer por la noche.", "text": "Elle est arrivée à Paris hier soir.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c958692f-a165-58ca-bc4a-90d7a4c57bf6.mp3"}, {"fr": "Mes sœurs sont parties en train ce matin.", "es": "Mis hermanas se fueron en tren esta mañana.", "text": "Mes sœurs sont parties en train ce matin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9068d2a6-9ff3-56b4-b8aa-61c3117e2f7d.mp3"}, {"fr": "Nous sommes restés trois jours à l''hôtel.", "es": "Nos quedamos tres días en el hotel.", "text": "Nous sommes restés trois jours à l''hôtel.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/dc42dde0-9f7b-586e-b66a-10cde773d866.mp3"}, {"fr": "J''ai quitté la ville et je suis allé à la mer.", "es": "Dejé la ciudad y fui al mar.", "text": "J''ai quitté la ville et je suis allé à la mer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e8550c84-9d62-5dda-9cd7-fed6a49e6513.mp3"}]'::jsonb, '[{"title": "«J''ai allé» no existe", "body": "El español dice «he ido», y el hispanohablante traduce con avoir. En francés aller es uno de los verbos de être: se dice «je suis allé», «nous sommes allés». Lo mismo con venir, partir, arriver, rester."}, {"title": "«Rester» no es restar, «quitter» no es quitar", "body": "«Rester» significa quedarse: «je suis resté à la maison» = me quedé en casa. Restar en matemáticas es «soustraire». «Quitter» significa dejar o abandonar un lugar, y necesita complemento: «je quitte Paris». Quitar un objeto es «enlever». Excepción fija al teléfono: «Ne quittez pas !»."}, {"title": "La concordancia no se oye, pero se escribe", "body": "«Elle est allée» suena igual que «il est allé»: la -e es muda. Aun así hay que escribirla. Solo se oye en participios como «mort → morte»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta en passé composé? (sujeto: je, masculino)", "options": ["je suis allé", "j''ai allé", "je suis alle"], "answer": "je suis allé", "id": "u9q1"}, {"type": "multiple_choice", "prompt": "¿Qué significa «Je suis resté à l''hôtel»?", "options": ["Me quedé en el hotel.", "Resté una noche del precio del hotel.", "Quité mis cosas del hotel."], "answer": "Me quedé en el hotel.", "id": "u9q2"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto (sujeto: elle, verbo aller).", "text": "Elle ___ allée au musée.", "answer": "est", "accepted": ["est"], "id": "u9q3"}, {"type": "multiple_choice", "prompt": "El sujeto «elles» es femenino plural. ¿Cuál es el participio correcto?", "options": ["Elles sont parties en vacances.", "Elles sont partis en vacances.", "Elles sont parti en vacances."], "answer": "Elles sont parties en vacances.", "id": "u9q4"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto (sujeto: nous, verbo quitter, que usa avoir).", "text": "Nous ___ quitté la ville à midi.", "answer": "avons", "accepted": ["avons"], "id": "u9q5"}]'::jsonb)
