insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 10, 'A2', 'Comer fuera y comprar', 'Aprende a comparar (plus, moins, aussi... que) con los irregulares meilleur y mieux, y a expresar cantidades con «de». Todo aplicado al restaurante y a las compras.', '[{"heading": "Comparar: plus / moins / aussi + adjetivo + que", "body": "Para comparar dos cosas, pon el adjetivo entre la palabra de comparación y «que». El adjetivo concuerda con el sujeto: «Cette pizza est plus chère que la salade». Es el mismo esquema que «más/menos/tan... que» del español.", "bullets": ["plus... que = más... que", "moins... que = menos... que", "aussi... que = tan... que", "El adjetivo concuerda: chère, chers, chères"]}, {"heading": "Los irregulares: meilleur y mieux", "body": "Al comparar, «plus bon» no se dice: se usa «meilleur» (adjetivo, acompaña a un nombre). Con un verbo, el comparativo de «bien» es «mieux» (adverbio, invariable). Pregúntate: ¿describo una cosa o cómo se hace algo?", "bullets": ["meilleur = adjetivo: «Ce vin est meilleur»", "meilleure, meilleurs, meilleures concuerdan", "mieux = adverbio con verbo: «Il cuisine mieux»", "mieux nunca cambia de forma"]}, {"heading": "Cantidades: beaucoup DE, un peu DE, trop DE", "body": "Tras una expresión de cantidad va «de» solo, sin artículo: «beaucoup de pain», «un peu de lait», «trop de sucre». Ante vocal o h muda se escribe «d''»: «beaucoup d''eau». Sirve igual en la mesa y en la tienda.", "bullets": ["beaucoup de, un peu de, trop de, assez de", "Nunca «du», «de la» ni «des» detrás", "Ante vocal: d''eau, d''argent, d''huile", "Un kilo de tomates, une bouteille d''eau"]}]'::jsonb, '[{"fr": "L''addition, s''il vous plaît !", "es": "¡La cuenta, por favor!", "text": "L''addition, s''il vous plaît !", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/02dc510b-28dc-5fee-b216-806d5d853d0c.mp3"}, {"fr": "Ce restaurant est meilleur que l''autre, mais il y a trop de monde.", "es": "Este restaurante es mejor que el otro, pero hay demasiada gente.", "text": "Ce restaurant est meilleur que l''autre, mais il y a trop de monde.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/10e87504-ff16-57b5-a8bd-73ade844b891.mp3"}, {"fr": "Je voudrais un peu de pain et une bouteille d''eau.", "es": "Quisiera un poco de pan y una botella de agua.", "text": "Je voudrais un peu de pain et une bouteille d''eau.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2fdad513-88cf-5c79-a874-22d9cf31b94d.mp3"}, {"fr": "Gardez la monnaie, on mange mieux ici qu''à la maison !", "es": "Quédese con el cambio, ¡aquí se come mejor que en casa!", "text": "Gardez la monnaie, on mange mieux ici qu''à la maison !", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4f8e9955-599a-54c3-a235-980ad2fa6921.mp3"}]'::jsonb, '[{"title": "Al comparar cualidades, «bon» no lleva «plus»", "body": "Al comparar cualidades, «bon» nunca lleva «plus»: se dice «meilleur». «Ce gâteau est plus bon» ✗ → «Ce gâteau est meilleur» ✓. (En la tienda sí oirás «plus bon marché».)"}, {"title": "meilleur (adjetivo) vs mieux (adverbio)", "body": "«meilleur» describe una cosa o persona: «un meilleur café». «mieux» dice cómo se hace algo, con un verbo: «il cuisine mieux». «Il chante meilleur» ✗ y «un mieux café» ✗ no existen."}, {"title": "«l''addition» y «la monnaie» no son lo que parecen", "body": "«addition» también significa suma, pero en el restaurante es LA CUENTA. «la monnaie» es el cambio o la vuelta; una moneda suelta es «une pièce»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Ce fromage est ___ que l''autre.» (este queso está mejor)", "options": ["meilleur", "plus bon", "mieux"], "answer": "meilleur", "id": "u10q1"}, {"type": "multiple_choice", "prompt": "Elige la forma correcta: «Ma sœur cuisine ___ que moi.» (cocina mejor)", "options": ["mieux", "meilleur", "plus bien"], "answer": "mieux", "id": "u10q2"}, {"type": "multiple_choice", "prompt": "En el restaurante pides la cuenta. ¿Qué dices?", "options": ["L''addition, s''il vous plaît", "La monnaie, s''il vous plaît", "La pièce, s''il vous plaît"], "answer": "L''addition, s''il vous plaît", "id": "u10q3"}, {"type": "multiple_choice", "prompt": "Completa: «Il y a beaucoup ___ monde ici.»", "options": ["de", "du", "des"], "answer": "de", "id": "u10q4"}, {"type": "multiple_choice", "prompt": "Completa: «Je voudrais une bouteille ___ eau.»", "options": ["d''", "de", "du"], "answer": "d''", "id": "u10q5"}]'::jsonb)
