insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 12, 'A2', 'Salud, cuerpo y consejos', 'Aprende a decir qué te duele con «avoir mal à» y sus contracciones (au, aux), y a dar consejos con «il faut» y «tu devrais».', '[{"heading": "«Avoir mal à» + las partes del cuerpo", "body": "Para decir que algo te duele, el francés usa «avoir mal à» + la parte del cuerpo. La preposición «à» es OBLIGATORIA: sin ella la frase no existe. Después va el artículo del cuerpo (le, la, l'', les), que se contrae con «à» en dos casos.", "bullets": ["J''ai mal à la tête. / J''ai mal à la gorge.", "à + le = au → J''ai mal au dos, au ventre.", "à + les = aux → J''ai mal aux dents, aux yeux.", "Ante vocal o h: à l'' → J''ai mal à l''estomac."]}, {"heading": "Aconsejar con «il faut» y «tu devrais»", "body": "Los dos van seguidos de INFINITIVO. «Il faut» es impersonal y suena a norma o necesidad general. «Tu devrais» es el condicional de «devoir» y suena mucho más suave y personal: es el consejo amable de amigo a amigo.", "bullets": ["Il faut boire beaucoup d''eau. (norma general)", "Tu devrais te reposer. (consejo amable)", "«Il faut» no cambia nunca: siempre «il».", "Negativo: «Il ne faut pas fumer» = no se DEBE fumar."]}, {"heading": "En la farmacia: vocabulario útil", "body": "Para explicar tu estado usas «être» o «avoir». Cuidado con «constipé», que NO significa acatarrado. Aprende estas fórmulas de memoria y evitarás un malentendido incómodo en la pharmacie.", "bullets": ["Je suis enrhumé(e) = estoy acatarrado/a.", "Je suis fatigué(e). / J''ai de la fièvre.", "J''ai une toux sèche. / Je tousse beaucoup.", "Une ordonnance = una receta médica."]}]'::jsonb, '[{"fr": "J''ai mal à la tête depuis ce matin.", "es": "Me duele la cabeza desde esta mañana.", "text": "J''ai mal à la tête depuis ce matin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/067dfcfb-1934-50eb-9e85-bcd9981233e1.mp3"}, {"fr": "Mon frère a mal au dos et aux dents.", "es": "A mi hermano le duele la espalda y le duelen los dientes.", "text": "Mon frère a mal au dos et aux dents.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6755d0d9-b34e-5746-aa3d-0d173d8219ed.mp3"}, {"fr": "Il faut prendre ce médicament après le repas.", "es": "Hay que tomar este medicamento después de la comida.", "text": "Il faut prendre ce médicament après le repas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b1eca1a8-8e32-538b-b633-455bcfe6f2d4.mp3"}, {"fr": "Tu devrais rester à la maison aujourd''hui.", "es": "Deberías quedarte en casa hoy.", "text": "Tu devrais rester à la maison aujourd''hui.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f13199b5-9079-5524-942c-6d2e0313b9d8.mp3"}]'::jsonb, '[{"title": "«J''ai mal la tête» ✗ — falta «à»", "body": "En español decimos «me duele la cabeza», sin preposición, y el hispanohablante la calca. En francés «à» es obligatoria: J''ai mal À la tête. Sin «à» la frase es agramatical."}, {"title": "«à le dos» ✗ — se contrae en «au dos»", "body": "«à + le» nunca se escriben separados: se funden en «au». Y «à + les» se funde en «aux». Di J''ai mal AU dos, J''ai mal AUX dents. Con «la» y «l''» no hay contracción: à la gorge, à l''estomac."}, {"title": "«Je suis constipé» = ESTOY ESTREÑIDO", "body": "Falso amigo peligroso en la farmacia. «Constipé» significa estreñido, no acatarrado. Para decir que estás resfriado usa «Je suis enrhumé(e)» o «J''ai un rhume»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Te duele la espalda (le dos). ¿Cuál es la forma correcta en francés?", "options": ["J''ai mal au dos.", "J''ai mal le dos.", "J''ai mal de dos."], "answer": "J''ai mal au dos.", "id": "u12q1"}, {"type": "multiple_choice", "prompt": "Completa: «J’ai mal ___ dents» (à + les).", "options": ["aux", "au", "à les"], "answer": "aux", "id": "u12q2"}, {"type": "cloze", "prompt": "Completa con la fórmula impersonal del consejo general (dos palabras).", "text": "Pour aller mieux, ___ boire beaucoup d’eau.", "answer": "il faut", "accepted": ["il faut"], "id": "u12q3"}, {"type": "multiple_choice", "prompt": "En la farmacia quieres decir «estoy acatarrado». ¿Qué dices?", "options": ["Je suis enrhumé.", "Je suis constipé.", "Je suis fatigué."], "answer": "Je suis enrhumé.", "id": "u12q4"}, {"type": "multiple_choice", "prompt": "Consejo suave con «devoir» para «tú». ¿Cuál es el condicional?", "options": ["Tu devrais te reposer.", "Tu devais te reposer.", "Tu devrai te reposer."], "answer": "Tu devrais te reposer.", "id": "u12q5"}]'::jsonb)
